function addMonths(date, count) {
  return new Date(date.getFullYear(), date.getMonth() + count, 1);
}

function hexToRgb(hex) {
  const normalized = hex.replace("#", "");
  const full = normalized.length === 3
    ? normalized.split("").map((char) => char + char).join("")
    : normalized;
  return {
    r: parseInt(full.slice(0, 2), 16),
    g: parseInt(full.slice(2, 4), 16),
    b: parseInt(full.slice(4, 6), 16)
  };
}

function colorWithAlpha(hex, alpha) {
  const { r, g, b } = hexToRgb(hex);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

function partyColorForPerson(person) {
  const affiliations = person.partyAffiliations || [];
  const primary = affiliations[0];
  const party = primary ? parties.find((row) => row.id === primary.partyId) : null;
  return party && party.color ? party.color : "#888888";
}

function assignPersonGuideSlots(people) {
  const left = [];
  const right = [];
  people.forEach((person) => {
    const leaning = Number(person.leaningScore) || 0;
    const intensity = Math.abs(leaning);
    if (leaning < 0) {
      left.push({ id: person.id, intensity });
    } else {
      right.push({ id: person.id, intensity });
    }
  });
  left.sort((a, b) => b.intensity - a.intensity);
  right.sort((a, b) => b.intensity - a.intensity);
  const slots = {};
  left.forEach((entry, index) => {
    slots[entry.id] = { side: -1, lineNumber: index + 1 };
  });
  right.forEach((entry, index) => {
    slots[entry.id] = { side: 1, lineNumber: index + 1 };
  });
  return slots;
}

function personCardPolygonPoints(dateFrom, dateTo, side, lineNumber, angleDeg, params) {
  if (!stage || !zzDirection) {
    return null;
  }

  const stageRect = stage.getBoundingClientRect();
  const stageHeight = stage.offsetHeight;
  const pFrom = dateToProgress(dateFrom);
  const pTo = dateToProgress(dateTo);
  if (pTo <= pFrom) {
    return null;
  }

  const yFrom = stageRect.top + pFrom * stageHeight;
  const yTo = stageRect.top + pTo * stageHeight;
  const zzDir = zzDirection.unit;
  const zzLineFrom = lineFromPointAndDir(timelineCenterPointAtViewportY(yFrom, angleDeg), zzDir);
