function intersectPolylineWithLine(polyline, line) {
  for (let index = 0; index < polyline.length - 1; index += 1) {
    const segment = lineFromPoints(polyline[index], polyline[index + 1]);
    const point = intersectLines(line, segment);
    if (point) {
      return point;
    }
  }
  return null;
}

function guideViewportPolyline(side, lineNumber, angleDeg, params, isPink) {
  return PERSON_STRIPE_GUIDE_XS.map((x) => {
    if (isPink) {
      const projected = projectedPinkLocalPoint(side, lineNumber, x, angleDeg, params);
      return guideLocalPointToViewport(projected.x, projected.y, angleDeg, params);
    }
    const y = guideLocalY(side, lineNumber, x);
    return guideLocalPointToViewport(x, y, angleDeg, params);
  });
}

function viewportYForDate(date) {
  const stageRect = stage.getBoundingClientRect();
  return stageRect.top + dateToProgress(date) * stage.offsetHeight;
}

function timeSliceLine(viewportY, angleDeg) {
  const origin = timelineCenterPointAtViewportY(viewportY, angleDeg);
  const dir = zzDirection && zzDirection.unit ? zzDirection.unit : { x: 0, y: -1 };
  return lineFromPointAndDir(origin, dir);
}

function personStripeCorners(birth, death, side, lineNumber, angleDeg, params) {
  if (!stage || !zzDirection) {
    return null;
  }
  if (death <= birth) {
    return null;
  }

  const yBirth = viewportYForDate(birth);
  const yDeath = viewportYForDate(death);
  if (yDeath <= yBirth) {
    return null;
  }

  const blackGuide = guideViewportPolyline(side, lineNumber, angleDeg, params, false);
  const pinkGuide = guideViewportPolyline(side, lineNumber, angleDeg, params, true);
  const sliceBirth = timeSliceLine(yBirth, angleDeg);
  const sliceDeath = timeSliceLine(yDeath, angleDeg);

  const blackBirth = intersectPolylineWithLine(blackGuide, sliceBirth);
  const pinkBirth = intersectPolylineWithLine(pinkGuide, sliceBirth);
  const pinkDeath = intersectPolylineWithLine(pinkGuide, sliceDeath);
  const blackDeath = intersectPolylineWithLine(blackGuide, sliceDeath);
  if (!blackBirth || !pinkBirth || !pinkDeath || !blackDeath) {
    return null;
  }

  const toLocal = (point) => viewportPointToGuideLocal(point.x, point.y, angleDeg, params);
  return [toLocal(blackBirth), toLocal(pinkBirth), toLocal(pinkDeath), toLocal(blackDeath)];
}

function personStripePoints(corners) {
  return corners.map((point) => `${point.x},${point.y}`).join(" ");
}

