  const maxScroll = document.documentElement.scrollHeight - window.innerHeight;
  return maxScroll > 0 ? clamp((window.scrollY / maxScroll) * SCROLL_TIME_FACTOR, 0, 1) : 0;
}

function updateTimeline() {
